</template>

<script setup lang="js">
import { ref, computed, onMounted } from 'vue'
import MusicPlayer from '~/components/head/MusicPlayer.vue'

const props = defineProps({
  onSwitch: { type: Function, required: true },
  switchLightDark: { type: Function, required: true },
  isDark: { type: Boolean, default: false },
})
const showMusicPlayer = ref(false)
const isPlaying = ref(false)
function handlePlayingStateChange(state) {
  isPlaying.value = state
}
// 太阳/月亮图标路径（保持不变）
const sunPath =
  'M9.165 14.836Q8 13.67 8 12t1.165-2.835T12 8t2.836 1.165T16 12t-1.164 2.836T12 16t-2.835-1.164M2 12.5q-.213 0-.357-.143T1.5 12t.143-.357T2 11.5h2.5q.214 0 .357.143T5 12t-.143.357t-.357.143zm17.5 0q-.213 0-.357-.143T19 12t.143-.357t.357-.143H22q.214 0 .357.143T22.5 12t-.143.357T22 12.5zm-7.857-7.643Q11.5 4.713 11.5 4.5V2q0-.213.143-.357T12 1.5t.357.143T12.5 2v2.5q0 .214-.143.357T12 5t-.357-.143m0 17.5Q11.5 22.214 11.5 22v-2.5q0-.213.143-.357T12 19t.357.143t.143.357V22q0 .214-.143.357T12 22.5t-.357-.143M6.362 7.03l-1.44-1.396q-.147-.14-.144-.344t.143-.37q.166-.165.36-.165t.354.165L7.05 6.342q.16.166.16.354q0 .189-.16.354q-.14.166-.332.153t-.356-.172m12.004 12.048l-1.416-1.421q-.16-.166-.16-.357t.16-.351q.14-.165.332-.153t.356.172l1.44 1.397q.147.14.144.344t-.143.369q-.166.165-.36.165t-.354-.165M16.95 7.05q-.165-.14-.153-.332t.172-.356l1.397-1.44q.14-.147.344-.144t.369.143q.165.166.165.36t-.165.354L17.658 7.05q-.166.16-.354.16t-.354-.16M4.921 19.079q-.165-.166-.165-.36t.165-.354l1.421-1.415q.166-.16.357-.16q.192 0 .351.16q.146.14.134.332t-.153.356l-1.397 1.44q-.159.166-.353.163q-.195-.002-.36-.162'

const moonPath =
  'M12.058 20q-3.333 0-5.667-2.334T4.058 12q0-2.47 1.413-4.535q1.414-2.067 4.01-2.973q.306-.107.536-.056t.381.199t.192.38q.04.233-.063.489q-.194.477-.282.971T10.158 7.5q0 2.673 1.863 4.537q1.864 1.863 4.537 1.863q.698 0 1.277-.148q.58-.148.988-.24q.218-.04.399.01t.292.176q.115.125.156.308t-.047.417q-.715 2.45-2.803 4.013T12.058 20'

const STORAGE_KEY = 'fortune_today'

const fortuneValue = ref(0)
const isFortuneLocked = ref(false) // 是否已计算过（当天不可再点）
// 圆环周长
const circumference = 2 * Math.PI * 20 // ≈125.66

// 进度偏移量
const dashOffset = computed(() => {
  return circumference * (1 - fortuneValue.value / 100)
})
// 根据人品值获取进度条颜色
const progressBarColor = computed(() => {
  const val = fortuneValue.value
  if (val >= 80) return '#2ecc71' // 绿色
  if (val >= 60) return '#f1c40f' // 黄色
  if (val >= 30) return '#e67e22' // 橙色
  return '#e74c3c' // 红色
})

// 随机生成人品值（0-100）
const generateFortune = () => {
  return Math.floor(Math.random() * 101)
}

// 获取今天的日期字符串（YYYY-MM-DD）
const getTodayStr = () => {
  const today = new Date()
  return `${today.getFullYear()}-${today.getMonth() + 1}-${today.getDate()}`
}

// 存储人品值到 localStorage
const saveFortune = (value) => {
  const data = {
    value,
    date: getTodayStr(),
  }
  localStorage.setItem(STORAGE_KEY, JSON.stringify(data))
}

// 从 localStorage 读取人品值，如果日期不是今天则返回 null
const loadFortune = () => {
  const stored = localStorage.getItem(STORAGE_KEY)
  if (!stored) return null
  try {
    const { value, date } = JSON.parse(stored)
    if (date === getTodayStr()) {
      return value
    }
  } catch (e) {
    console.warn('Failed to parse stored fortune', e)
  }
  return null
}

// 更新人品值（点击时调用）
const updateFortune = () => {
  if (isFortuneLocked.value) return // 已计算过，不能再点
  const newValue = generateFortune()
  fortuneValue.value = newValue
  saveFortune(newValue)
  isFortuneLocked.value = true
}
const tooltipText = computed(() => {
  if (!isFortuneLocked.value) return '今日人品'
  return getToolTip()
})
// 根据人品值返回不同的悬浮提示语
const getToolTip = () => {
  const val = fortuneValue.value
  if (val >= 90) return '✨ 欧皇附体！✨'
  if (val >= 70) return '🌟 今天运气不错哟～ 🌟'
  if (val >= 50) return '🍀 普普通通，明天会更好 🍀'
  if (val >= 30) return '🌧️ 运势低迷，但别灰心 🌧️'
  if (val >= 10) return '🔥 这...这不对吧 🔥'
  if (val < 10) return '⚡️ 额...是百分制哦~⚡️'
}

// 初始化：读取存储，如果当天有值则显示并锁定，否则按钮可点且显示默认值0（或显示“？”）
const initFortune = () => {
  const stored = loadFortune()
  if (stored !== null) {
    fortuneValue.value = stored
    isFortuneLocked.value = true
  } else {
    // 当天尚未计算，显示默认0（或显示“？”），按钮可点击
    fortuneValue.value = 0
    isFortuneLocked.value = false
  }
}

// 组件挂载时初始化
onMounted(() => {
  initFortune()
})
</script>

<style scoped lang="scss">
@import '../../../assets/css/main';

.function-buttons {
  position: fixed;
  top: 20px;
  right: 20px;
  z-index: 1000;
  display: flex;
  gap: 12px;

  @media (max-width: 640px) {
    top: 12px;
    right: 12px;
    gap: 8px;
  }
}

button {
  @extend .cursor-solid;
  position: relative;
  width: 48px;
  height: 48px;
  border-radius: 50%;
  background: v-bind(
    '!props.isDark ? "rgba(30,30,40,0.6)" : "rgba(255,255,255,0.2)"'
  );
  backdrop-filter: blur(12px);
  border: 1px solid
    v-bind('props.isDark ? "rgba(255,255,255,0.25)" : "rgba(255,255,255,0.4)"');
  color: white;
  transition: all 0.25s cubic-bezier(0.2, 0.9, 0.4, 1.1);
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);

  &:hover {
    transform: scale(1.08);
    background: v-bind(
      'props.isDark ? "rgba(50,50,70,0.8)" : "rgba(255,255,255,0.35)"'
    );
    border-color: v-bind(
      'props.isDark ? "rgba(255,255,255,0.5)" : "rgba(255,255,255,0.6)"'
    );
    box-shadow: 0 8px 20px rgba(0, 0, 0, 0.2);
  }

  &:active {
    transform: scale(0.96);
    transition-duration: 0.1s;
  }

  .icon {
    width: 24px;
    height: 24px;
    transition: transform 0.2s;
  }

  @media (max-width: 640px) {
    width: 40px;
    height: 40px;
    .icon {
      width: 20px;
      height: 20px;
    }
  }
}

/* 音乐按钮旋转动画 */
.music-button.playing .icon {
  animation: spin 2s linear infinite;
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}

/* 统一 tooltip 样式 */
[class$='-button']::after,
.fortune-button::after {
  content: attr(data-tooltip);
  position: absolute;
  bottom: -36px;
